const simulateClick = (element) => {
  if (!element) return;
  // Bắn thêm PointerEvent để tương thích tốt nhất với các UI Framework hiện đại
  element.dispatchEvent(new PointerEvent('pointerdown', { bubbles: true, cancelable: true, view: window }));
  element.dispatchEvent(new MouseEvent('mousedown', { bubbles: true, cancelable: true, view: window }));
  element.dispatchEvent(new PointerEvent('pointerup', { bubbles: true, cancelable: true, view: window }));
  element.dispatchEvent(new MouseEvent('mouseup', { bubbles: true, cancelable: true, view: window }));
  element.click();
};

let retries = 0;
const maxRetries = 10;

const checkAndClick = setInterval(() => {
  const switchBtn = document.querySelector('[data-test-id="team-list-advanced-search-switch"]');

  if (switchBtn) {
    clearInterval(checkAndClick);

    // 1. Lấy biến an toàn qua hàm chuẩn của Automa (tránh lỗi render string)
    let isSearchAdvanced = false;
    try {
      const val = automaRefData('variables', 'isSearchAdvanced');
      isSearchAdvanced = (val === true || val === 'true');
    } catch(e) {
      // Fallback
      isSearchAdvanced = (`{{variables.isSearchAdvanced}}` === 'true');
    }

    const isCurrentlyChecked = switchBtn.getAttribute('aria-checked') === 'true';

    // 2. So sánh state để click
    if (isSearchAdvanced && !isCurrentlyChecked) {
      simulateClick(switchBtn);
    } else if (!isSearchAdvanced && isCurrentlyChecked) {
      simulateClick(switchBtn);
    }

    // 3. Chờ 500ms để React/Vue cập nhật DOM (aria-checked) rồi mới đi sang node Conditions
    setTimeout(() => {
      automaNextBlock();
    }, 500);

  } else if (retries >= maxRetries) {
    clearInterval(checkAndClick);
    console.error("Timeout: Cannot find advanced search switch");
    automaNextBlock(); // Vẫn next để luồng không bị kẹt
  }
  retries++;
}, 500);

