let retries = 0;
const maxRetries = 20; // Sẽ chờ tối đa 10 giây (20 lần x 500ms) để API search trả về

const checkAndClickAdd = setInterval(() => {
  // 1. Lấy biến LDAP cần tìm
  let targetLdap = '';
  try {
    targetLdap = automaRefData('variables', 'searchLdap') || '';
  } catch(e) {
    targetLdap = `{{variables.searchLdap}}`;
  }

  targetLdap = targetLdap.trim().toLowerCase();

  if (!targetLdap || targetLdap.includes('{{')) {
     clearInterval(checkAndClickAdd);
     console.error("Lỗi: Biến searchLdap rỗng hoặc chưa được gán giá trị!");
     automaNextBlock();
     return;
  }

  // 2. Tìm tất cả các dòng dữ liệu trong bảng hiện tại
  const rows = document.querySelectorAll('tr.ant-table-row');
  let clicked = false;

  for (let row of rows) {
    // 3. Tìm các thẻ span trong dòng. Nếu text chứa đúng LDAP cần tìm thì xác định là Match
    const spans = row.querySelectorAll('span');
    let isMatch = false;

    for (let span of spans) {
      if (span.innerText && span.innerText.trim().toLowerCase() === targetLdap) {
        isMatch = true;
        break;
      }
    }

    // Nếu đúng dòng của người cần tìm
    if (isMatch) {
      // 4. Tìm nút có chữ "Add" trong dòng đó và Click
      const buttons = row.querySelectorAll('button');
      for (let btn of buttons) {
        if (btn.innerText && btn.innerText.includes('Add')) {
          simulateClick(btn);
          clicked = true;
          break;
        }
      }
    }

    if (clicked) break; // Thoát vòng lặp các dòng nếu đã click
  }

  // 5. Xử lý sau khi duyệt bảng
  if (clicked) {
    clearInterval(checkAndClickAdd);
    // Chờ 500ms cho UI xử lý hiệu ứng Click/API rồi cho luồng Automa đi tiếp
    setTimeout(() => {
      automaNextBlock();
    }, 500);
  } else if (retries >= maxRetries) {
    clearInterval(checkAndClickAdd);
    console.error(`Timeout: Đã chờ 10s nhưng API chưa load ra người có LDAP là '${targetLdap}', hoặc nút Add bị ẩn.`);
    automaNextBlock(); // Hết thời gian thì bỏ qua để luồng không bị kẹt
  }

  retries++;
}, 500);

(async () => {
  const sleep = (ms) => new Promise(r => setTimeout(r, ms));
  const simulateClick = (element) => {
    if (!element) return;
    element.dispatchEvent(new PointerEvent('pointerdown', { bubbles: true, cancelable: true, view: window }));
    element.dispatchEvent(new MouseEvent('mousedown', { bubbles: true, cancelable: true, view: window }));
    element.dispatchEvent(new PointerEvent('pointerup', { bubbles: true, cancelable: true, view: window }));
    element.dispatchEvent(new MouseEvent('mouseup', { bubbles: true, cancelable: true, view: window }));
    element.click();
  };
  const simulateInput = (element, text) => {
    element.focus();
    const setter = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, "value").set;
    if (setter) setter.call(element, text);
    else element.value = text;
    element.dispatchEvent(new Event('input', { bubbles: true }));
  };
  const waitForOptions = async (maxRetries = 20) => {
    for (let i = 0; i < maxRetries; i++) {
      const options = document.querySelectorAll('.ant-select-dropdown:not(.ant-select-dropdown-hidden) .ant-select-item-option');
      if (options.length > 0) return Array.from(options);
      await sleep(500);
    }
    return [];
  };

  try {
    let targetLdap = '';
    try { targetLdap = automaRefData('variables', 'addEmployeeLdap') || ''; } 
    catch(e) { targetLdap = `{{variables.addEmployeeLdap}}`; }
    if (targetLdap.includes('{{')) targetLdap = '';
    targetLdap = targetLdap.trim().toLowerCase();

    const selector = document.querySelector('.ant-drawer .ant-select-selector');
    const searchInput = document.querySelector('.ant-drawer .ant-select-selection-search-input');
    if (!selector || !searchInput) {
      console.error("[QC Automa] Lỗi: Không tìm thấy ô Select Employee trong Drawer");
      return automaNextBlock({ $error: true });
    }

    simulateClick(selector);
    let options = await waitForOptions();
    options = options.filter(opt => !opt.classList.contains('ant-select-item-option-disabled') && !opt.getAttribute('aria-disabled'));

    let matchOption = null;
    if (targetLdap !== '') {
      simulateInput(searchInput, targetLdap);
      await sleep(1000);
      options = await waitForOptions();
      options = options.filter(opt => !opt.classList.contains('ant-select-item-option-disabled') && !opt.getAttribute('aria-disabled'));
      for (let opt of options) {
        const text = (opt.innerText || opt.textContent).toLowerCase();
        if (text.includes(targetLdap)) {
          matchOption = opt;
          break;
        }
      }
    }
    if (!matchOption && options.length > 0) {
      matchOption = options[Math.floor(Math.random() * options.length)];
    }

    if (matchOption) {
      simulateClick(matchOption); 
      await sleep(500); 
    } else {
      console.error("[QC Automa] Lỗi: Không có bất kỳ option nào khả dụng để chọn.");
      return automaNextBlock({ $error: true });
    }


    // --- XỬ LÝ DATE PICKERS ---
    // 1. Join Date (Bắt buộc)
    const dateInputs = document.querySelectorAll('.ant-picker-input input[placeholder="Select date"]');
    if (dateInputs.length > 0) {
      simulateClick(dateInputs[0]); // Join Date
      await sleep(500);
      const todayBtn = document.querySelector('.ant-picker-today-btn');
      if (todayBtn) { simulateClick(todayBtn); await sleep(500); }
    }

    // 2. Expected Leave Date (Tùy chọn)
    let fillLeave = false;
    try { fillLeave = automaRefData('variables', 'fillExpectedLeaveDate') === true || automaRefData('variables', 'fillExpectedLeaveDate') === 'true'; } 
    catch(e) { fillLeave = `{{variables.fillExpectedLeaveDate}}` === 'true'; }

    if (fillLeave && dateInputs.length > 1) {
      simulateClick(dateInputs[1]); // Expected Leave Date
      await sleep(500);
      const todayBtn = document.querySelector('.ant-picker-today-btn');
      if (todayBtn) { simulateClick(todayBtn); await sleep(500); }
    }
    // -------------------------


    // Click nút Add to Team dưới chân Drawer
    const addBtn = document.querySelector('.ant-drawer-footer .ant-btn-primary');
    if (addBtn) simulateClick(addBtn);

    await sleep(1000); // Chờ Dialog Confirm (Overlap)
    const modalConfirm = document.querySelector('.ant-modal-content');
    if (modalConfirm) {
      let forceMove = false;
      try { forceMove = automaRefData('variables', 'confirmOverlap') === true || automaRefData('variables', 'confirmOverlap') === 'true'; } 
      catch(e) { forceMove = `{{variables.confirmOverlap}}` === 'true'; }
      if (forceMove) {
        const confirmBtn = modalConfirm.querySelector('.ant-modal-footer .ant-btn-primary');
        if (confirmBtn) simulateClick(confirmBtn);
      } else {
        const cancelBtn = modalConfirm.querySelector('.ant-modal-footer .ant-btn-default');
        if (cancelBtn) simulateClick(cancelBtn);
      }
    }
  } catch (error) {
    console.error("[QC Automa] Lỗi script:", error);
    return automaNextBlock({ $error: true });
  }

  setTimeout(() => automaNextBlock(), 500);
})();
